/* CoreUp V36 auto-render bridge. Never installs a no-op renderer. */
(function(){
  function bridge(){
    if(window.CoreUpTypesetMathV36){ window.renderMathInElement=function(el){ window.CoreUpTypesetMathV36(el); }; }
  }
  if(document.readyState==='loading') document.addEventListener('DOMContentLoaded', bridge); else bridge();
  window.addEventListener('load', bridge);
})();
